import{AUDIO_LIST}from"./audioList.js";class AudioManager{constructor(){this.sounds={},this.loops={}}async loadAll(){var o=Object.keys(AUDIO_LIST);0!==o.length&&(o=o.map(s=>new Promise(o=>{let e=new Audio;e.src=AUDIO_LIST[s],e.preload="auto",e.addEventListener("canplaythrough",()=>{this.sounds[s]=e,o()},{once:!0}),e.addEventListener("error",()=>{console.error(`[AudioManager]: Ошибка загрузки звукового файла по ключу: "${s}" `+`(Путь: ${AUDIO_LIST[s]})`),o()},{once:!0})})),await Promise.all(o),console.log(`[AudioManager]: Все звуковые ассеты (${Object.keys(this.sounds).length}) успешно импортированы и кэшированы!`))}play(e,o=.5){var s=this.sounds[e];s?((s=s.cloneNode()).volume=o,s.play().catch(o=>{console.warn(`[AudioManager]: Воспроизведение звука "${e}" заблокировано политикой браузера. Нужен клик по Canvas.`,o)})):console.warn(`[AudioManager]: Попытка сыграть несуществующий звук по ключу: "${e}"`)}playLoop(e,s,o=.5){var a;this.loops[e]||((a=this.sounds[s])?((a=a.cloneNode()).loop=!0,a.volume=o,(this.loops[e]=a).play().catch(o=>{console.warn(`[AudioManager]: Loop-звук "${s}" заблокирован браузером.`,o),delete this.loops[e]})):console.warn(`[AudioManager]: Попытка запустить loop несуществующего звука: "${s}"`))}stopLoop(o){var e=this.loops[o];e&&(e.pause(),e.currentTime=0,delete this.loops[o])}stopAllLoops(){Object.keys(this.loops).forEach(o=>{this.stopLoop(o)})}}let audioManager=new AudioManager;export{audioManager};